const businesses = $('Fetch Active Businesses').first().json;
const items = Array.isArray(businesses) ? businesses : [businesses];
return items.filter(b => b.id && b.site_url).map(b => ({
  json: {
    businessId: b.id,
    businessName: b.name,
    siteUrl: b.site_url,
    repoName: b.repo_name,
    source: 'scheduled'
  }
}));

const webhook = $('Webhook POST /test-app').first().json;
return [{
  json: {
    businessId: webhook.body.businessId,
    businessName: webhook.body.businessName || webhook.body.businessId,
    siteUrl: webhook.body.siteUrl,
    repoName: webhook.body.repoName,
    source: 'webhook'
  }
}];

// Normalize input from either trigger
const item = $input.first().json;
const siteUrl = item.siteUrl.replace(/\/$/, '');
return [{
  json: {
    businessId: item.businessId,
    businessName: item.businessName,
    siteUrl: siteUrl,
    repoName: item.repoName,
    source: item.source,
    timestamp: new Date().toISOString(),
    today: new Date().toISOString().split('T')[0]
  }
}];

const params = $('Normalize Input').first().json;
const pages = [
  { name: 'Landing Page (/)', node: 'Test Landing Page' },
  { name: 'Login (/login)', node: 'Test Login Page' },
  { name: 'Signup (/signup)', node: 'Test Signup Page' },
  { name: 'Contact (/contact)', node: 'Test Contact Page' },
  { name: 'Demo (/demo)', node: 'Test Demo Page' },
  { name: 'Blog (/blog)', node: 'Test Blog Page' },
  { name: 'API Health (/api/health)', node: 'Test API Health' }
];

const results = [];
for (const page of pages) {
  try {
    const res = $(page.node).first().json;
    const statusCode = res.statusCode || res.status || 0;
    const isHealth = page.name.includes('/api/health');
    if (statusCode === 200) {
      results.push({ page: page.name, status: 'PASS', statusCode, detail: 'OK' });
    } else if (statusCode === 404 && isHealth) {
      results.push({ page: page.name, status: 'SKIP', statusCode, detail: 'API health endpoint not configured (optional)' });
    } else if (statusCode === 404) {
      results.push({ page: page.name, status: 'WARN', statusCode, detail: 'Page not found (404)' });
    } else if (statusCode >= 500) {
      results.push({ page: page.name, status: 'FAIL', statusCode, detail: `Server error (${statusCode})` });
    } else if (statusCode === 0) {
      results.push({ page: page.name, status: 'FAIL', statusCode: 0, detail: 'Connection failed or timeout' });
    } else {
      results.push({ page: page.name, status: 'WARN', statusCode, detail: `Unexpected status code ${statusCode}` });
    }
  } catch (e) {
    results.push({ page: page.name, status: 'FAIL', statusCode: 0, detail: 'Error: ' + e.message });
  }
}

// Store landing page HTML for SEO and link checker suites
let landingHtml = '';
try {
  const landingRes = $('Test Landing Page').first().json;
  landingHtml = (landingRes.body || landingRes.data || '').toString();
} catch (e) {
  landingHtml = '';
}

return [{ json: { pageLoadResults: results, landingHtml } }];

const raw = $('PageSpeed Insights').first().json;
let performance = null, accessibility = null, seo = null, error = null;
try {
  if (raw.lighthouseResult) {
    const cats = raw.lighthouseResult.categories;
    performance = Math.round((cats.performance?.score || 0) * 100);
    accessibility = Math.round((cats.accessibility?.score || 0) * 100);
    seo = Math.round((cats.seo?.score || 0) * 100);
  } else {
    error = raw.error?.message || 'PageSpeed returned no results';
  }
} catch (e) {
  error = 'Failed to parse PageSpeed response: ' + e.message;
}

const results = [];
if (error) {
  results.push({ test: 'PageSpeed Insights', status: 'FAIL', detail: error });
} else {
  results.push({ test: 'Performance >= 50', status: performance >= 50 ? 'PASS' : 'FAIL', score: performance, detail: `Score: ${performance}/100` });
  results.push({ test: 'Accessibility >= 80', status: accessibility >= 80 ? 'PASS' : 'FAIL', score: accessibility, detail: `Score: ${accessibility}/100` });
  results.push({ test: 'SEO >= 80', status: seo >= 80 ? 'PASS' : 'FAIL', score: seo, detail: `Score: ${seo}/100` });
}

return [{ json: { performanceResults: results, scores: { performance, accessibility, seo } } }];

const params = $('Normalize Input').first().json;
const landingHtml = $('Parse Page Load Results').first().json.landingHtml;
const fullHtml = landingHtml;
const html = landingHtml.toLowerCase();

const results = [];

if (!html || html.length < 100) {
  results.push({ test: 'Site Reachable for SEO', status: 'FAIL', detail: 'Could not fetch landing page HTML' });
  return [{ json: { seoResults: results } }];
}

// Title tag
const titleMatch = fullHtml.match(/<title[^>]*>([^<]+)<\/title>/i);
results.push({
  test: 'Title tag exists',
  status: titleMatch && titleMatch[1].trim().length > 0 ? 'PASS' : 'FAIL',
  detail: titleMatch ? `Title: "${titleMatch[1].trim().substring(0, 80)}"` : 'Missing <title> tag'
});

// Meta description
const metaDescMatch = fullHtml.match(/<meta[^>]*name\s*=\s*["']description["'][^>]*content\s*=\s*["']([^"']+)["']/i)
  || fullHtml.match(/<meta[^>]*content\s*=\s*["']([^"']+)["'][^>]*name\s*=\s*["']description["']/i);
results.push({
  test: 'Meta description exists',
  status: metaDescMatch ? 'PASS' : 'FAIL',
  detail: metaDescMatch ? `Description: "${metaDescMatch[1].substring(0, 80)}..."` : 'Missing meta description'
});

// OG image
const ogImageMatch = fullHtml.match(/<meta[^>]*property\s*=\s*["']og:image["'][^>]*>/i);
results.push({
  test: 'OG image exists',
  status: ogImageMatch ? 'PASS' : 'WARN',
  detail: ogImageMatch ? 'Found og:image tag' : 'Missing og:image meta tag'
});

// Favicon
const faviconMatch = fullHtml.match(/<link[^>]*rel\s*=\s*["'](icon|shortcut icon|apple-touch-icon)["'][^>]*>/i);
results.push({
  test: 'Favicon exists',
  status: faviconMatch ? 'PASS' : 'WARN',
  detail: faviconMatch ? 'Found favicon link' : 'Missing favicon link tag'
});

// H1 tag
const h1Match = fullHtml.match(/<h1[^>]*>/i);
results.push({
  test: 'H1 tag exists',
  status: h1Match ? 'PASS' : 'FAIL',
  detail: h1Match ? 'Found H1 tag' : 'Missing H1 tag'
});

// Canonical URL
const canonicalMatch = fullHtml.match(/<link[^>]*rel\s*=\s*["']canonical["'][^>]*>/i);
results.push({
  test: 'Canonical URL exists',
  status: canonicalMatch ? 'PASS' : 'WARN',
  detail: canonicalMatch ? 'Found canonical link' : 'Missing canonical URL'
});

// Robots meta not noindex
const robotsMetaMatch = fullHtml.match(/<meta[^>]*name\s*=\s*["']robots["'][^>]*content\s*=\s*["']([^"']+)["']/i);
if (robotsMetaMatch && robotsMetaMatch[1].toLowerCase().includes('noindex')) {
  results.push({ test: 'Not noindex', status: 'FAIL', detail: 'Page has noindex robots meta tag' });
} else {
  results.push({ test: 'Not noindex', status: 'PASS', detail: robotsMetaMatch ? `Robots: ${robotsMetaMatch[1]}` : 'No robots meta tag (defaults to index)' });
}

// JSON-LD structured data
const jsonLdMatch = fullHtml.match(/<script[^>]*type\s*=\s*["']application\/ld\+json["'][^>]*>/i);
results.push({
  test: 'Structured data (JSON-LD) exists',
  status: jsonLdMatch ? 'PASS' : 'WARN',
  detail: jsonLdMatch ? 'Found JSON-LD structured data' : 'Missing JSON-LD structured data'
});

return [{ json: { seoResults: results } }];

const params = $('Normalize Input').first().json;
const landingHtml = $('Parse Page Load Results').first().json.landingHtml;

if (!landingHtml || landingHtml.length < 100) {
  return [{ json: { linkResults: [{ test: 'Link Checker', status: 'SKIP', detail: 'No landing page HTML to parse' }], brokenLinks: [] } }];
}

// Extract all href links
const hrefRegex = /<a[^>]*href\s*=\s*["']([^"'#]+)["'][^>]*>/gi;
const links = new Set();
let match;
while ((match = hrefRegex.exec(landingHtml)) !== null) {
  let href = match[1].trim();
  // Only internal links
  if (href.startsWith('/')) {
    href = params.siteUrl + href;
    links.add(href);
  } else if (href.startsWith(params.siteUrl)) {
    links.add(href);
  }
}

// Return links to check (limit to 20 to avoid abuse)
const linkArray = Array.from(links).slice(0, 20);
return linkArray.map(url => ({ json: { url, siteUrl: params.siteUrl } }));

const items = $('Check Link').all();
const extractedItems = $('Extract Internal Links').all();
const results = [];
const brokenLinks = [];

for (let i = 0; i < items.length; i++) {
  const res = items[i].json;
  const url = extractedItems[i]?.json?.url || 'unknown';
  const statusCode = res.statusCode || res.status || 0;
  if (statusCode >= 200 && statusCode < 400) {
    results.push({ url, status: 'PASS', statusCode, detail: 'OK' });
  } else if (statusCode === 404) {
    results.push({ url, status: 'FAIL', statusCode, detail: 'Broken link (404)' });
    brokenLinks.push(url);
  } else if (statusCode >= 500) {
    results.push({ url, status: 'FAIL', statusCode, detail: `Server error (${statusCode})` });
    brokenLinks.push(url);
  } else {
    results.push({ url, status: 'WARN', statusCode, detail: `Status ${statusCode}` });
  }
}

return [{ json: { linkResults: results, brokenLinks } }];

const params = $('Normalize Input').first().json;

// === Suite 1: Page Load Results ===
const pageLoadResults = $('Parse Page Load Results').first().json.pageLoadResults;

// === Suite 2: SEO & Meta Results ===
const seoResults = $('SEO & Meta Checks').first().json.seoResults;

// Sitemap and Robots.txt
let sitemapStatus = 'FAIL';
let robotsStatus = 'FAIL';
try {
  const sitemapRes = $('Test Sitemap.xml').first().json;
  const sitemapCode = sitemapRes.statusCode || sitemapRes.status || 0;
  sitemapStatus = sitemapCode === 200 ? 'PASS' : 'WARN';
} catch (e) { sitemapStatus = 'WARN'; }
try {
  const robotsRes = $('Test Robots.txt').first().json;
  const robotsCode = robotsRes.statusCode || robotsRes.status || 0;
  robotsStatus = robotsCode === 200 ? 'PASS' : 'WARN';
} catch (e) { robotsStatus = 'WARN'; }

seoResults.push({ test: 'Sitemap.xml returns 200', status: sitemapStatus, detail: sitemapStatus === 'PASS' ? 'Found sitemap.xml' : 'sitemap.xml not found' });
seoResults.push({ test: 'Robots.txt returns 200', status: robotsStatus, detail: robotsStatus === 'PASS' ? 'Found robots.txt' : 'robots.txt not found' });

// === Suite 3: Performance Results ===
const performanceResults = $('Parse PageSpeed').first().json.performanceResults;
const scores = $('Parse PageSpeed').first().json.scores;

// === Suite 4: Link Checker Results ===
let linkResults = [];
let brokenLinks = [];
try {
  const lr = $('Parse Link Results').first().json;
  linkResults = lr.linkResults || [];
  brokenLinks = lr.brokenLinks || [];
} catch (e) {
  linkResults = [{ test: 'Link Checker', status: 'SKIP', detail: 'No links to check' }];
}

// === Suite 5: Console Error Check ===
let consoleResult = { test: 'Browser Console Errors', status: 'SKIP', detail: 'Browser Use not configured' };
try {
  const consoleRes = $('Browser Console Check').first().json;
  if (consoleRes.id || consoleRes.result) {
    const output = (consoleRes.result || consoleRes.output || '').toString().toLowerCase();
    if (output.includes('no console errors') || output.includes('no errors')) {
      consoleResult = { test: 'Browser Console Errors', status: 'PASS', detail: 'No JavaScript console errors detected' };
    } else {
      consoleResult = { test: 'Browser Console Errors', status: 'WARN', detail: 'Console errors found: ' + (consoleRes.result || consoleRes.output || '').toString().substring(0, 500) };
    }
  }
} catch (e) { /* SKIP */ }

// === Suite 6: Functional Signup Test ===
let signupResult = { test: 'Signup Flow', status: 'SKIP', detail: 'Browser Use not configured' };
try {
  const signupRes = $('Browser Signup Test').first().json;
  if (signupRes.id || signupRes.result) {
    const output = (signupRes.result || signupRes.output || '').toString().toLowerCase();
    if (output.includes('success') || output.includes('account created') || output.includes('welcome')) {
      signupResult = { test: 'Signup Flow', status: 'PASS', detail: 'Signup test passed' };
    } else if (output.includes('fail') || output.includes('error')) {
      signupResult = { test: 'Signup Flow', status: 'FAIL', detail: 'Signup test failed: ' + (signupRes.result || signupRes.output || '').toString().substring(0, 500) };
    } else {
      signupResult = { test: 'Signup Flow', status: 'WARN', detail: 'Signup result unclear: ' + (signupRes.result || signupRes.output || '').toString().substring(0, 500) };
    }
  }
} catch (e) { /* SKIP */ }

// === Aggregate all results ===
const allResults = [];

// Suite 1
for (const r of pageLoadResults) {
  allResults.push({ suite: 'Page Load', test: r.page, status: r.status, detail: r.detail });
}

// Suite 2
for (const r of seoResults) {
  allResults.push({ suite: 'SEO & Meta', test: r.test, status: r.status, detail: r.detail });
}

// Suite 3
for (const r of performanceResults) {
  allResults.push({ suite: 'Performance', test: r.test, status: r.status, detail: r.detail });
}

// Suite 4
if (linkResults.length > 0 && linkResults[0].test) {
  allResults.push({ suite: 'Link Checker', test: linkResults[0].test, status: linkResults[0].status, detail: linkResults[0].detail });
} else {
  for (const r of linkResults) {
    allResults.push({ suite: 'Link Checker', test: r.url || 'Link', status: r.status, detail: r.detail });
  }
}

// Suite 5
allResults.push({ suite: 'Console Errors', ...consoleResult });

// Suite 6
allResults.push({ suite: 'Functional Tests', ...signupResult });

// === Calculate health score ===
const scorable = allResults.filter(r => r.status !== 'SKIP');
const passed = scorable.filter(r => r.status === 'PASS').length;
const warned = scorable.filter(r => r.status === 'WARN').length;
const failed = scorable.filter(r => r.status === 'FAIL').length;
const total = scorable.length;
const healthScore = total > 0 ? Math.round(((passed + warned * 0.5) / total) * 100) : 0;

const failures = allResults.filter(r => r.status === 'FAIL');
const warnings = allResults.filter(r => r.status === 'WARN');

// === Generate markdown report ===
let report = `# App Test Report: ${params.businessName}\n\n`;
report += `**Date:** ${params.today}\n`;
report += `**Site:** ${params.siteUrl}\n`;
report += `**Health Score:** ${healthScore}/100\n`;
report += `**Results:** ${passed} passed, ${warned} warnings, ${failed} failed, ${allResults.filter(r => r.status === 'SKIP').length} skipped\n\n`;

if (scores.performance !== null) {
  report += `## Lighthouse Scores\n`;
  report += `- Performance: ${scores.performance}/100 ${scores.performance >= 50 ? 'PASS' : 'FAIL'}\n`;
  report += `- Accessibility: ${scores.accessibility}/100 ${scores.accessibility >= 80 ? 'PASS' : 'FAIL'}\n`;
  report += `- SEO: ${scores.seo}/100 ${scores.seo >= 80 ? 'PASS' : 'FAIL'}\n\n`;
}

const suites = ['Page Load', 'SEO & Meta', 'Performance', 'Link Checker', 'Console Errors', 'Functional Tests'];
for (const suite of suites) {
  const suiteResults = allResults.filter(r => r.suite === suite);
  if (suiteResults.length === 0) continue;
  report += `## ${suite}\n`;
  for (const r of suiteResults) {
    const icon = r.status === 'PASS' ? 'PASS' : r.status === 'FAIL' ? 'FAIL' : r.status === 'WARN' ? 'WARN' : 'SKIP';
    report += `- ${icon} | ${r.test} | ${r.detail}\n`;
  }
  report += `\n`;
}

if (failures.length > 0) {
  report += `## Failures Requiring Action\n`;
  for (const f of failures) {
    report += `- [${f.suite}] ${f.test}: ${f.detail}\n`;
  }
  report += `\n`;
}

if (brokenLinks.length > 0) {
  report += `## Broken Links\n`;
  for (const link of brokenLinks) {
    report += `- ${link}\n`;
  }
  report += `\n`;
}

return [{
  json: {
    businessId: params.businessId,
    businessName: params.businessName,
    siteUrl: params.siteUrl,
    repoName: params.repoName,
    source: params.source,
    today: params.today,
    healthScore,
    passed,
    warned,
    failed,
    total,
    failures,
    warnings,
    brokenLinks,
    report,
    allResults
  }
}];

const results = $('Aggregate All Results').first().json;
const failures = results.failures;

// Group failures by suite
const grouped = {};
for (const f of failures) {
  const key = f.suite;
  if (!grouped[key]) grouped[key] = [];
  grouped[key].push(f);
}

const issues = [];
for (const [suite, items] of Object.entries(grouped)) {
  let body = `## App Test Failure: ${suite}\n\n`;
  body += `**Business:** ${results.businessName}\n`;
  body += `**Site:** ${results.siteUrl}\n`;
  body += `**Date:** ${results.today}\n`;
  body += `**Health Score:** ${results.healthScore}/100\n\n`;
  body += `### Failures\n\n`;
  for (const item of items) {
    body += `- **${item.test}**: ${item.detail}\n`;
  }
  body += `\n### Expected\nAll tests in this suite should PASS.\n\n`;
  body += `### Actual\n${items.length} test(s) FAILED.\n\n`;
  body += `---\n*Auto-created by App Tester Agent*`;

  issues.push({
    json: {
      title: `@claude [App Test FAIL] ${suite}: ${items.map(i => i.test).join(', ').substring(0, 120)}`,
      body,
      repoName: results.repoName
    }
  });
}

return issues;
